from flask import Flask, request, jsonify
import pickle
import os

app = Flask(__name__)

# Load pre-trained models
pre_trained_models = {
    'model1': 'path/to/model1.pkl',
    'model2': 'path/to/model2.pkl'
}

@app.route('/upload_model', methods=['POST'])
def upload_model():
    if request.method == 'POST':
        file = request.files['file']
        model_name = request.form.get('model_name')
        
        # Check if model name already exists
        if model_name in pre_trained_models:
            return jsonify({'error': 'Model name already exists'}), 400
        
        try:
            with open(os.path.join('models', f'{model_name}.pkl'), 'wb') as f:
                pickle.dump(pickle.load(file), f)
            return jsonify({'message': 'Model uploaded successfully'}), 201
        except Exception as e:
            return jsonify({'error': str(e)}), 500

@app.route('/inference/<string:model_name>', methods=['POST'])
def inference(model_name):
    if model_name not in pre_trained_models and model_name not in os.listdir('models'):
        return jsonify({'error': 'Model not found'}), 404
    
    try:
        with open(os.path.join('models', f'{model_name}.pkl'), 'rb') as f:
            model = pickle.load(f)
        
        # Perform inference
        input_data = request.get_json()
        prediction = model.predict(input_data)
        return jsonify({'prediction': prediction.tolist()}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)